@app.route('/api/v1/register', methods=['POST'])
@rate_limit
def register_annotator():
    """Register a new annotator."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or len(username) < 3 or len(username) > 50:
        return jsonify({'error': 'Username must be 3-50 characters'}), 400

    import re
    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return jsonify({'error': 'Username must be alphanumeric with underscores only'}), 400

    if len(password) < 12:
        return jsonify({'error': 'Password must be at least 12 characters'}), 400

    # Generate API key
    api_key = secrets.token_urlsafe(32)
    api_key_hash = hashlib.sha256(api_key.encode()).hexdigest()
    password_hash = generate_password_hash(password)

    db = get_db()
    try:
        db.execute(
            'INSERT INTO annotators (username, password_hash, api_key_hash) VALUES (?, ?, ?)',
            (username, password_hash, api_key_hash)
        )
        db.commit()
        logger.info(f"New annotator registered: {username}")
        log_audit(None, 'register', f'New annotator: {username}')
        return jsonify({
            'message': 'Registration successful',
            'api_key': api_key,
            'warning': 'Store your API key securely. It cannot be retrieved later.'
        }), 201
    except sqlite3.IntegrityError:
        return jsonify({'error': 'Username already exists'}), 409


