@app.route('/api/v1/images', methods=['GET'])
@rate_limit
@require_api_key
def list_images():
    """List images available for labeling."""
    page = max(1, request.args.get('page', 1, type=int))
    per_page = min(100, max(1, request.args.get('per_page', 20, type=int)))
    unlabeled_only = request.args.get('unlabeled_only', 'false').lower() == 'true'
    offset = (page - 1) * per_page

    db = get_db()

    if unlabeled_only:
        # Images not yet labeled by this annotator
        rows = db.execute('''
            SELECT i.id, i.image_hash, i.image_path, i.created_at,
                   COUNT(l.id) as annotation_count
            FROM images i
            LEFT JOIN labels l ON i.id = l.image_id
            WHERE i.id NOT IN (
                SELECT image_id FROM labels WHERE annotator_id = ?
            )
            GROUP BY i.id
            ORDER BY annotation_count ASC, i.created_at ASC
            LIMIT ? OFFSET ?
        ''', (g.current_annotator['id'], per_page, offset)).fetchall()
    else:
        rows = db.execute('''
            SELECT i.id, i.image_hash, i.image_path, i.created_at,
                   COUNT(l.id) as annotation_count
            FROM images i
            LEFT JOIN labels l ON i.id = l.image_id
            GROUP BY i.id
            ORDER BY i.created_at DESC
            LIMIT ? OFFSET ?
        ''', (per_page, offset)).fetchall()

    images = []
    for row in rows:
        images.append({
            'id': row['id'],
            'image_hash': row['image_hash'],
            'image_path': row['image_path'],
            'annotation_count': row['annotation_count'],
            'created_at': row['created_at']
        })

    return jsonify({'images': images, 'page': page, 'per_page': per_page}), 200


@app.route('/api/v1/annotations', methods=['POST'])
@rate_limit
@require_api_key
def submit_annotation():
    """Submit a label annotation for an image."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    image_id = data.get('image_id')
    label = sanitize_label(data.get('label', ''))
    confidence = data.get('confidence', 1.0)

    if not isinstance(image_id, int) or image_id < 1:
        return jsonify({'error': 'Valid image_id required'}), 400

    if not label:
        return jsonify({'error': 'Valid label required'}), 400

    if ALLOWED_LABELS and label not in ALLOWED_LABELS:
        return jsonify({
            'error': f'Label not in allowed set. Allowed: {sorted(ALLOWED_LABELS)}'
        }), 400

    if not isinstance(confidence, (int, float)) or confidence < 0 or confidence > 1:
        return jsonify({'error': 'Confidence must be between 0 and 1'}), 400

    db = get_db()

    # Verify image exists
    image = db.execute('SELECT id FROM images WHERE id = ?', (image_id,)).fetchone()
    if not image:
        return jsonify({'error': 'Image not found'}), 404

    annotator_id = g.current_annotator['id']

    try:
        db.execute(
            'INSERT INTO labels (image_id, annotator_id, label, confidence) VALUES (?, ?, ?, ?)',
            (image_id, annotator_id, label, confidence)
        )
        db.commit()
        log_audit(annotator_id, 'submit_annotation', f'Image {image_id}: {label}')

        # Check if we should compute consensus
        annotation_count = db.execute(
            'SELECT COUNT(*) as cnt FROM labels WHERE image_id = ?',
            (image_id,)
        ).fetchone()['cnt']

        result = {
            'message': 'Annotation submitted successfully',
            'annotation_count': annotation_count
        }

        if annotation_count >= app.config['MIN_ANNOTATIONS_FOR_CONSENSUS']:
            consensus = _compute_consensus(db, image_id)
            if consensus:
                result['consensus'] = consensus

        return jsonify(result), 201

    except sqlite3.IntegrityError:
        return jsonify({'error': 'You have already annotated this image'}), 409


