def compute_all_consensus():
    """Recompute consensus for all images with sufficient annotations (admin only)."""
    db = get_db()
    min_annotations = app.config['MIN_ANNOTATIONS_FOR_CONSENSUS']

    images = db.execute('''
        SELECT image_id, COUNT(*) as cnt
        FROM labels
        GROUP BY image_id
        HAVING cnt >= ?
    ''', (min_annotations,)).fetchall()

    results = []
    for img in images:
        consensus = _compute_consensus(db, img['image_id'])
        if consensus:
            consensus['image_id'] = img['image_id']
            results.append(consensus)

    log_audit(g.current_annotator['id'], 'compute_all_consensus', f'{len(results)} images processed')
    return jsonify({
        'message': f'Consensus computed for {len(results)} images',
        'results': results
    }), 200


