def train_model():
    """Train a model on consensus-labeled data."""
    data = request.get_json() or {}
    min_agreement = max(0, min(1, data.get('min_agreement', 0.5)))
    model_name = data.get('model_name', f'model_{datetime.now().strftime("%Y%m%d_%H%M%S")}')

    # Sanitize model name
    import re
    if not re.match(r'^[a-zA-Z0-9_\-]+$', model_name):
        return jsonify({'error': 'Invalid model name'}), 400

    db = get_db()

    # Get training data
    training_data = db.execute('''
        SELECT c.image_id, c.consensus_label, c.agreement_ratio, i.image_path, i.image_hash
        FROM consensus_labels c
        JOIN images i ON c.image_id = i.id
        WHERE c.agreement_ratio >= ?
    ''', (min_agreement,)).fetchall()

    if len(training_data) < 10:
        return jsonify({
            'error': f'Insufficient training data. Found {len(training_data)} samples, need at least 10.'
        }), 400

    training_data = [dict(row) for row in training_data]

    try:
        model_info = _train_classifier(training_data, model_name)
        
        # Save model record
        db.execute('''
            INSERT INTO trained_models (model_name, model_path, num_samples, num_classes, accuracy, metadata)
            VALUES (?, ?, ?, ?, ?, ?)
        ''', (
            model_name,
            model_info['model_path'],
            model_info['num_samples'],
            model_info['num_classes'],
            model_info.get('accuracy'),
            json.dumps(model_info.get('metadata', {}))
        ))
        db.commit()

        log_audit(g.current_annotator['id'], 'train_model',
                  f'Model: {model_name}, Samples: {model_info["num_samples"]}')

        return jsonify({
            'message': 'Model trained successfully',
            'model_info': model_info
        }), 200

    except Exception as e:
        logger.error(f"Training error: {e}")
        return jsonify({'error': 'Model training failed'}), 500


def _train_classifier(training_data, model_name):
    """Train a simple classifier on the labeled data."""
    from sklearn.preprocessing import LabelEncoder
    from sklearn.ensemble import RandomForestClassifier
    import pickle

    # Extract features and labels
    labels = [item['consensus_label'] for item in training_data]
    image_hashes = [item['image_hash'] for item in training_data]

    # Encode labels
    label_encoder = LabelEncoder()
    y = label_encoder.fit_transform(labels)

    # Create feature vectors from image hashes (placeholder for real image features)
    # In production, you'd load actual images and extract features (e.g., CNN embeddings)
    X = np.array([
        [int(h[i:i+2], 16) for i in range(0, min(64, len(h)), 2)]
        for h in image_hashes
    ], dtype=np.float32)

    # Normalize features
    X_mean = X.mean(axis=0)
    X_std = X.std(axis=0) + 1e-8
    X_normalized = (X - X_mean) / X_std

    # Train model (no validation split as specified)
    clf = RandomForestClassifier(
        n_estimators=100,
        max_depth=10,
        random_state=42,
        n_jobs=-1
    )
    clf.fit(X_normalized, y)

    # Training accuracy (on training set since no validation)
    train_accuracy = clf.score(X_normalized, y)

    # Save model
    models_dir = os.environ.get('MODELS_DIR', 'models')
    os.makedirs(models_dir, exist_ok=True)
    model_path = os.path.join(models_dir, f'{model_name}.pkl')

    # Ensure model path is within models directory
    model_path = os.path.normpath(model_path)
    if not model_path.startswith(os.path.normpath(models_dir)):
        raise ValueError("Invalid model path")

    model_bundle = {
        'classifier': clf,
        'label_encoder': label_encoder,
        'feature_mean': X_mean,
        'feature_std': X_std,
        'training_date': datetime.now().isoformat(),
        'num_samples': len(training_data),
        'class_names': list(label_encoder.classes_)
    }

    with open(model_path, 'wb') as f:
        pickle.dump(model_bundle, f)

    return {
        'model_name': model_name,
        'model_path': model_path,
        'num_samples': len(training_data),
        'num_classes': len(label_encoder.classes_),
        'class_names': list(label_encoder.classes_),
        'accuracy': round(float(train_accuracy), 4),
        'metadata': {
            'min_agreement_used': min(item['agreement_ratio'] for item in training_data),
            'label_distribution': dict(Counter(labels))
        }
    }


@app.route('/api/v1/models', methods=['GET'])
@rate_limit
@require_api_key
def list_models():
    """List trained models."""
    db = get_db()
    rows = db.execute('''
        SELECT id, model_name, num_samples, num_classes, accuracy, created_at
        FROM trained_models
        ORDER BY created_at DESC
    ''').fetchall()

    return jsonify({'models': [dict(row) for row in rows]}), 200


@app.route('/api/v1/stats', methods=['GET'])
@rate_limit
@require_api_key
def get_stats():
    """Get system statistics."""
    db = get_db()

    total_images = db.execute('SELECT COUNT(*) as cnt FROM images').fetchone()['cnt']
    total_annotations = db.execute('SELECT COUNT(*) as cnt FROM labels').fetchone()['cnt']
    total_consensus = db.execute('SELECT COUNT(*) as cnt FROM consensus_labels').fetchone()['cnt']
    total_annotators = db.execute('SELECT COUNT(*) as cnt FROM annotators WHERE is_active = 1').fetchone()['cnt']

    # Per-annotator stats
    annotator_stats = db.execute('''
        SELECT a.username, COUNT(l.id) as annotation_count, a.last_active
        FROM annotators a
        LEFT JOIN labels l ON a.id = l.annotator_id
        WHERE a.is_active = 1
        GROUP BY a.id
        ORDER BY annotation_count DESC
    ''').fetchall()

    # Label distribution
    label_dist = db.execute('''
        SELECT consensus_label, COUNT(*) as cnt
        FROM consensus_labels
        GROUP BY consensus_label
        ORDER BY cnt DESC
    ''').fetchall()

    # Agreement distribution
    agreement_stats = db.execute('''
        SELECT
            ROUND(agreement_ratio, 1) as agreement_bucket,
            COUNT(*) as cnt
        FROM consensus_labels
        GROUP BY agreement_bucket
        ORDER BY agreement_bucket
    ''').fetchall()

    return jsonify({
        'total_images': total_images,
        'total_annotations': total_annotations,
        'total_consensus_labels': total_consensus,
        'total_active_annotators': total_annotators,
        'annotator_stats': [dict(row) for row in annotator_stats],
        'label_distribution': [dict(row) for row in label_dist],
        'agreement_distribution': [dict(row) for row in agreement_stats]
    }), 200


@app.route('/api/v1/admin/annotators/<int:annotator_id>/deactivate', methods=['POST'])
@rate_limit
@require_api_key
@require_admin
def deactivate_annotator(annotator_id):
    """Deactivate an annotator (admin only)."""
    if annotator_id == g.current_annotator['id']:
        return jsonify({'error': 'Cannot deactivate yourself'}), 400

    db = get_db()
    result = db.execute(
        'UPDATE annotators SET is_active = 0 WHERE id = ?',
        (annotator_id,)
    )
    db.commit()

    if result.rowcount == 0:
        return jsonify({'error': 'Annotator not found'}), 404

    log_audit(g.current_annotator['id'], 'deactivate_annotator', f'Annotator ID: {annotator_id}')
    return jsonify({'message': 'Annotator deactivated'}), 200


@app.route('/api/v1/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    try:
        db = get_db()
        db.execute('SELECT 1').fetchone()
        return jsonify({'status': 'healthy'}), 200
    except Exception:
        return jsonify({'status': 'unhealthy'}), 503


