def create_admin_user():
    """Create initial admin user if none exists."""
    with app.app_context():
        db = get_db()
        admin = db.execute('SELECT id FROM annotators WHERE is_admin = 1').fetchone()
        if not admin:
            admin_password = os.environ.get('ADMIN_PASSWORD')
            if not admin_password:
                admin_password = secrets.token_urlsafe(16)
                logger.info(f"Generated admin password: {admin_password}")

            api_key = secrets.token_urlsafe(32)
            api_key_hash = hashlib.sha256(api_key.encode()).hexdigest()

            db.execute(
                'INSERT INTO annotators (username, password_hash, api_key_hash, is_admin) VALUES (?, ?, ?, 1)',
                ('admin', generate_password_hash(admin_password), api_key_hash)
            )
            db.commit()
            logger.info(f"Admin API key: {api_key}")
            logger.info("Store these credentials securely!")


if __name__ == '__main__':
    with app.app_context():
        init_db()
        create_admin_user()

    # In production, use gunicorn or similar WSGI server
    debug_mode = os.environ.get('FLASK_DEBUG', 'false').lower() == 'true'
    host = os.environ.get('FLASK_HOST', '127.0.0.1')
    port = int(os.environ.get('FLASK_PORT', 5000))

    app.run(
        host=host,
        port=port,
        debug=debug_mode
    )